import{_ as a,o,c as d,a2 as e}from"./chunks/framework.BnBoz4Zl.js";const i="/anjian-workbuddy-bluebook-site/assets/001_image_T8L2bOcbBo.CUiu18Ez.png",r="/anjian-workbuddy-bluebook-site/assets/002_image_TlTJbNIQOo.wfLvLGps.png",l="/anjian-workbuddy-bluebook-site/assets/003_image_Hfv9bPfcIo.BxNpZYhf.png",s="/anjian-workbuddy-bluebook-site/assets/004_20260708204254_Nvfjb5QwFo.CXRUDStA.gif",n="/anjian-workbuddy-bluebook-site/assets/005_image_Bzc4b6Ukko.OOg2cP6W.png",p="/anjian-workbuddy-bluebook-site/assets/006_image_Oz4wbqMTqo.zA9GTMHp.png",b="/anjian-workbuddy-bluebook-site/assets/007_image_TDP4b0emBo.V1wE0Z86.png",_="/anjian-workbuddy-bluebook-site/assets/008_image_MHngbV84ro.HQSr0W9m.png",u="/anjian-workbuddy-bluebook-site/assets/009_image_LUaZbwcddo.DJbSPOHu.png",w=JSON.parse('{"title":"第 6 章 WorkBuddy的专家和专家团","description":"WorkBuddy 本身是一个通用 Agent，什么任务都能接。但通用不意味着每个领域都应该用同一种方式处理。 同样是分析一份销售数据，普通 Agent 可能会读取数据、生成图表、总结趋势。数据分析专家会先理解业务目标，再确定核心指标，检查数据质量，寻找异常变化，分析可能原因，最后给出可以执行的业务建议。","frontmatter":{},"headers":[],"relativePath":"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 6 章 WorkBuddy的专家和专家团/index.md","filePath":"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 6 章 WorkBuddy的专家和专家团/index.md","lastUpdated":1784770175000}'),k={name:"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/第 6 章 WorkBuddy的专家和专家团/index.md"};function c(g,t,m,h,y,f){return o(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="第-6-章-workbuddy的专家和专家团" tabindex="-1">第 6 章 WorkBuddy的专家和专家团 <a class="header-anchor" href="#第-6-章-workbuddy的专家和专家团" aria-label="Permalink to &quot;第 6 章 WorkBuddy的专家和专家团&quot;">​</a></h1><h2 id="专家和专家团与skill的区别" tabindex="-1">专家和专家团与Skill的区别 <a class="header-anchor" href="#专家和专家团与skill的区别" aria-label="Permalink to &quot;专家和专家团与Skill的区别&quot;">​</a></h2><p>WorkBuddy 本身是一个通用 Agent，什么任务都能接。但通用不意味着每个领域都应该用同一种方式处理。</p><p>比如，</p><p>同样是分析一份销售数据，普通 Agent 可能会读取数据、生成图表、总结趋势。数据分析专家会先理解业务目标，再确定核心指标，检查数据质量，寻找异常变化，分析可能原因，最后给出可以执行的业务建议。</p><p>同样是写一篇小红书文案，普通 Agent 可能更关注内容本身。小红书运营专家还会考虑选题、标题、开头留存、种草逻辑、平台内容生态和互动设计。</p><p>专家定义为一种角色切换机制，通过人设、方法论和工具链，让 WorkBuddy 以特定领域专家的身份执行任务。</p><p>最简单的理解是：</p><p>普通 WorkBuddy = 通用 AI 同事</p><p>专家 = 有明确岗位和专业经验的 AI 同事</p><p>而专家团定义为一种协作执行机制。一个专家团由多位专家组成，由团长自动拆解任务、分配工作、并行执行，最后整合交付。</p><p>用户只需要告诉团长客户背景、最新需求和预期成果，不需要自己挑选团员，也不需要自己拆分任务。团长会安排内容、活动、分析等成员协作，最后汇总完整方案。</p><table tabindex="0"><thead><tr><th>方式</th><th>本质</th><th>适合的问题</th></tr></thead><tbody><tr><td>普通任务</td><td>通用理解与执行</td><td>一次性的清楚任务</td></tr><tr><td>Skill</td><td>特定工具能力</td><td>需要稳定执行某个动作</td></tr><tr><td>专家</td><td>人设 + 方法论 + 工具链</td><td>明确领域的单点专业问题</td></tr><tr><td>专家团</td><td>多位专家 + 协作流程</td><td>需要拆解、并行、汇总的复杂项目</td></tr></tbody></table><h2 id="召唤一位专家" tabindex="-1">召唤一位专家 <a class="header-anchor" href="#召唤一位专家" aria-label="Permalink to &quot;召唤一位专家&quot;">​</a></h2><ol><li>打开“专家·技能·连接器”，选择“专家”；</li></ol><p><img src="'+i+'" alt="" loading="lazy"></p><ol start="2"><li>点击“召唤专家”；以“高考我帮你”专家举例</li></ol><p><img src="'+r+'" alt="" loading="lazy"></p><ol start="3"><li>提供任务内容，比如“帮我查一下2026年高考数学真题”</li></ol><p><img src="'+l+'" alt="" loading="lazy"></p><ol start="4"><li>等待结果</li></ol><h2 id="创建一位专家" tabindex="-1">创建一位专家 <a class="header-anchor" href="#创建一位专家" aria-label="Permalink to &quot;创建一位专家&quot;">​</a></h2><p>点击我的专家，创建专家，即可</p><p><img src="'+s+'" alt="" loading="lazy"></p><p>比如创建一个公众号创作专家，</p><p><img src="'+n+'" alt="" loading="lazy"></p><p>生成结束，可以测试</p><p><img src="'+p+'" alt="" loading="lazy"></p><p>在我的专家中，也可以找到。</p><p><img src="'+b+'" alt="" loading="lazy"></p><h2 id="召唤一个专家团" tabindex="-1">召唤一个专家团 <a class="header-anchor" href="#召唤一个专家团" aria-label="Permalink to &quot;召唤一个专家团&quot;">​</a></h2><p>专家团由团长负责拆解和汇总，成员按角色并行或串行执行。任务开始前先确认：成员分工是否覆盖完整、哪些步骤依赖前一步、什么时候需要人来拍板、最终由谁整合。</p><p>打开“专家·技能·连接器”，选择“专家团”，点击召唤</p><p><img src="'+_+'" alt="" loading="lazy"></p><p><img src="'+u+'" alt="" loading="lazy"></p>',35)])])}const W=a(k,[["render",c]]);export{w as __pageData,W as default};
